      return (
        <mock key={reconstruct ? 0 : 1} args={['parent']}>
          <mock
            args={['child']}
            ref={(self) => void (lastMounted = self?.uuid)}
            attach={(_, self) => {
              calls.push('attach')
              lastAttached = self.uuid
              return () => calls.push('detach')
