    // A should be mounted and visible and fallback should be unmounted.
    await act(async () => resolveA())
    await act(async () =>
      (
        await root.configure()
      ).render(
        <React.Suspense fallback={<Fallback />}>
          <AsyncPrimitive object={aPromise} />
