}

.content__img-wrap {
	position: relative;
	width: 80%;
	height: calc(100% - 13rem);
}

.content__img {
	position: absolute;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background: url(../img/large.jpg) no-repeat 50% 100%;
	background-size: cover;
	opacity: 0.7;
	will-change: transform;
}

.content__img:nth-child(1) {
	opacity: 0.3;
}

.content__img:nth-child(2) {
	opacity: 0.5;
}

.content__text {
	position: absolute;
	font-size: 10vw;
}

.js .content__text-inner {
	opacity: 0;
}

.grid {
	display: grid;
	padding: 1rem;
	margin: 0 auto;
	grid-template-columns: 100%;
	grid-row-gap: 4rem;
	grid-column-gap: 20vw;
	max-width: 1200px;
}

.grid__item {
	height: 60vh;
	max-height: 500px;
	position: relative;
}

.grid__item-img {
	position: relative;
	width: 100%;
	height: 100%;
	background-size: cover;
}

.grid__item-img::after {
	content: '';
	background: var(--color-overlay);
	position: absolute;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	mix-blend-mode: color-dodge;
	opacity: 0;
	transition: opacity 0.3s;
}

.grid__item:hover .grid__item-img::after {
	opacity: 1;
}

.grid__item-letter {
	position: absolute;
	bottom: -4vw;
	right: -4vw;
	z-index: 10;
	font-size: 15vw;
	line-height: 1;
}

@media screen and (min-width: 53em) {
	.message {
		display: none;
	}
	.frame {
		position: fixed;
		text-align: left;
		z-index: 10000;
		top: 0;
		left: 0;
		display: grid;
		align-content: space-between;
		width: 100%;
		max-width: none;
		height: 100vh;
		padding: 3rem;
		pointer-events: none;
		grid-template-columns: 75% 25%;
		grid-template-rows: auto auto auto;
		grid-template-areas: 'title links'
							'... ...'
							'github demos';
	}
	.frame__title-wrap {
		grid-area: title;
		display: flex;
	}
	.frame__title {
		margin: 0;
	}
	.frame__tagline {
		position: relative;
		margin: 0 0 0 1rem;
		padding: 0 0 0 1rem;
	}
	.frame__github {
		grid-area: github;
		justify-self: start;
		margin: 0;
	}
	.frame__demos {
		margin: 0;
		grid-area: demos;
		justify-self: end;
	}
	.frame__links {
		grid-area: links;
		padding: 0;
		justify-self: end;
	}
	.frame a {
		pointer-events: auto;
	}
	.content {
		height: 100vh;
		justify-content: center;
	}
	.grid {
		padding: 70vh 4rem;
		grid-template-columns: repeat(2,calc(50% - 10vw));
		grid-row-gap: 50vh;
	}
	.grid__item:nth-child(even) {
		margin-top: -45vh;
	}
}

